"""iOS background-time extension for long-running training.

By default iOS suspends apps ~30 seconds after the user moves them to
the background — even though the user clearly intended the training to
keep running. With `enable()`, this module asks `UIApplication` for a
`beginBackgroundTask` extension; iOS usually grants several minutes,
sometimes longer on AC power.

The extension is opt-in: doing nothing keeps the default iOS behavior.
The typical pattern is:

    import _cb_background as bg

    with bg.BackgroundSession():
        for step in range(n_steps):
            loss = train_step(batch)
            checkpointer.maybe_save(step, loss=loss.item())
            if bg.time_remaining() < 10:
                # iOS is about to suspend us — checkpoint & bail
                checkpointer.save(step)
                break

When you're in the foreground, `time_remaining()` returns +inf
(`UIApplication.backgroundTimeRemaining` reports `DBL_MAX` then).

For a more involved opt-in pattern that uses `BGProcessingTaskRequest`
to schedule longer runs later, you'd need to declare a permitted
identifier in `Info.plist` first — out of scope for this helper.
"""
from __future__ import annotations
import ctypes
from typing import Optional

_lib: Optional[ctypes.CDLL] = None
_available: bool = False
_last_error: str = ""


def _init() -> bool:
    global _lib, _available, _last_error
    if _available:
        return True
    try:
        _lib = ctypes.CDLL(None)
    except Exception as e:
        _last_error = f"ctypes.CDLL(None) failed: {e}"
        return False

    needed = ("cb_bg_acquire", "cb_bg_release", "cb_bg_time_remaining")
    for sym in needed:
        if not hasattr(_lib, sym):
            _last_error = (f"`{sym}` not exported by the host executable — "
                           "BackgroundTimeManager.swift not linked in.")
            return False

    try:
        _lib.cb_bg_acquire.restype = None
        _lib.cb_bg_acquire.argtypes = []
        _lib.cb_bg_release.restype = None
        _lib.cb_bg_release.argtypes = []
        _lib.cb_bg_time_remaining.restype = ctypes.c_double
        _lib.cb_bg_time_remaining.argtypes = []
    except Exception as e:
        _last_error = f"argtype setup failed: {e}"
        return False

    _available = True
    _last_error = ""
    return True


def is_available() -> bool:
    """True if the Swift bridge is reachable and ready."""
    return _init()


def diagnose() -> str:
    """Empty string if working, else a one-line explanation."""
    _init()
    return "" if _available else _last_error


def enable():
    """Request a background-time extension. No-op when foregrounded
    or when the bridge isn't available."""
    if _init():
        _lib.cb_bg_acquire()


def disable():
    """Release the extension. Call when training ends."""
    if _init():
        _lib.cb_bg_release()


def time_remaining() -> float:
    """Seconds of background time left. Returns +inf when the app is
    in the foreground (since iOS reports DBL_MAX then). Returns +inf
    when the bridge isn't available (so polling loops degrade
    gracefully to standard CPU-bound behavior outside CodeBench)."""
    if _init():
        v = _lib.cb_bg_time_remaining()
        # Apple's API uses DBL_MAX (~1.8e308) for "not backgrounded".
        # That's mathematically equal to +inf when interpreted as a
        # signal — but expose it as float('inf') so user code can use
        # the standard idiom `if time_remaining() < threshold`.
        if v > 1e100:
            return float("inf")
        return float(v)
    return float("inf")


class BackgroundSession:
    """Context manager for the acquire/release pair.

        with BackgroundSession():
            train_loop()

    Acquires at __enter__, releases at __exit__. Safe to nest — each
    enable() / disable() call is idempotent at the iOS level (Swift
    side ignores re-acquires while already holding)."""

    def __enter__(self):
        enable()
        return self

    def __exit__(self, exc_type, exc_val, tb):
        disable()
        return False
